use strict;
use warnings;
use CGI qw(:standard);
use File::Spec;

my $log_dir = "/var/log/myapp";
my $cgi = CGI->new;

print $cgi->header('text/plain');

my $filename = $cgi->param('logfile');
if (!$filename) {
    print "No logfile specified";
    exit;
