# Canonicalize the path
my $resolved_path = File::Spec->rel2abs($filename, $log_dir);
my $canonical_path = File::Spec->canonpath($resolved_path);

# Validate that the path is within the allowed directory
if ($canonical_path !~ /^\Q$log_dir\E/) {
    print "Invalid logfile path";
    exit;
}

# Check for absolute paths or traversal
if ($filename =~ /^\// || $filename =~ /\.\./) {
    print "Invalid logfile path";
    exit;
}

# Open and display the file
open(my $fh, '<', "$log_dir/$filename") or do {
    print "Cannot open log file";
    exit;
